def detect_pfsense_version(vshell: PFClient) -> str:
    """
    Attempts to determine the version of pfSense running on the remote host.

    Returns:
        str: The version of pfSense running (e.g. 2.8.1, 25.11.1, 25.07, etc.)
    """
    version_raw = vshell.run_command("/bin/cat /etc/version")
    return version_raw.split("-")[0]


